        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new OrderUpdateModelMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[OrderUpdateModelMessage](sbeTemplateId=");
            builder.Append(OrderUpdateModelMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(OrderUpdateModelMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != OrderUpdateModelMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(OrderUpdateModelMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != OrderUpdateModelMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(OrderUpdateModelMessage.BlockLength);
            builder.Append("):");

            builder.Append("OrderStatus=");
            builder.Append(this.OrderStatus);
            builder.Append('|');
            builder.Append("ExecutionType=");
            builder.Append(this.ExecutionType);
            builder.Append('|');
            builder.Append("Price=");
            if (this.Price != null)
            {
                this.Price.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }
            builder.Append('|');
            builder.Append("AvgPrice=");
            if (this.AvgPrice != null)
            {
                this.AvgPrice.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }
            builder.Append('|');
            builder.Append("LastPrice=");
            if (this.LastPrice != null)
            {
                this.LastPrice.BuildString(builder);
            }
            else
            {
                builder.Append("null");
            }
            builder.Append('|');
            builder.Append("LastQty=");
            builder.Append(this.LastQty);
            builder.Append('|');
            builder.Append("CumQty=");
            builder.Append(this.CumQty);
            builder.Append('|');
            builder.Append("LeavesQty=");
            builder.Append(this.LeavesQty);
            builder.Append('|');
            builder.Append("Qty=");
            builder.Append(this.Qty);
            builder.Append('|');
            builder.Append("LastUpdateTime=");
            builder.Append(this.LastUpdateTime);
            builder.Append('|');
            builder.Append("IsCancelReject=");
            builder.Append(this.IsCancelReject);
            builder.Append('|');
            builder.Append("Side=");
            builder.Append(this.Side);
            builder.Append('|');
            builder.Append("ContraTrader=");
            builder.Append(this.ContraTrader);
            builder.Append('|');
            builder.Append("ClientOrderId=");
            builder.Append('\'').Append(GetClientOrderId()).Append('\'');
            builder.Append('|');
            builder.Append("PrevClientOrderId=");
            builder.Append('\'').Append(GetPrevClientOrderId()).Append('\'');
            builder.Append('|');
            builder.Append("OrigOrderId=");
            builder.Append('\'').Append(GetOrigOrderId()).Append('\'');
            builder.Append('|');
            builder.Append("OrderId=");
            builder.Append('\'').Append(GetOrderId()).Append('\'');
            builder.Append('|');
            builder.Append("LastExchange=");
            builder.Append('\'').Append(GetLastExchange()).Append('\'');
            builder.Append('|');
            builder.Append("Message=");
            builder.Append('\'').Append(GetMessage()).Append('\'');
            builder.Append('|');
            builder.Append("Route=");
            builder.Append('\'').Append(GetRoute()).Append('\'');

            this.Limit = originalLimit;

        }
